class Solution:
    def minGenerations(self, points, target):
        existing = set(tuple(p) for p in points)
        tgt = tuple(target)
        if tgt in existing:
            return 0
        gen = 0
        while True:
            gen += 1
            lst = list(existing)
            produced = set()
            for i in range(len(lst)):
                a = lst[i]
                for j in range(i + 1, len(lst)):
                    b = lst[j]
                    c = ((a[0] + b[0]) // 2, (a[1] + b[1]) // 2, (a[2] + b[2]) // 2)
                    produced.add(c)
            added = produced - existing
            if not added:
                return -1
            existing |= added
            if tgt in added:
                return gen

