var minGenerations = function(points, target) {
    const key = (p) => p[0] + ',' + p[1] + ',' + p[2];
    const existing = new Map();
    for (const p of points) existing.set(key(p), p);
    const tgtKey = key(target);
    if (existing.has(tgtKey)) return 0;
    let gen = 0;
    while (true) {
        gen++;
        const lst = Array.from(existing.values());
        const produced = new Map();
        for (let i = 0; i < lst.length; i++) {
            const a = lst[i];
            for (let j = i + 1; j < lst.length; j++) {
                const b = lst[j];
                const c = [
                    Math.floor((a[0] + b[0]) / 2),
                    Math.floor((a[1] + b[1]) / 2),
                    Math.floor((a[2] + b[2]) / 2),
                ];
                produced.set(key(c), c);
            }
        }
        let addedAny = false;
        for (const [k, v] of produced) {
            if (!existing.has(k)) {
                existing.set(k, v);
                addedAny = true;
                if (k === tgtKey) return gen;
            }
        }
        if (!addedAny) return -1;
    }
};
